"use strict";var xdropbox=new function(){this.select=function(linkType,onSuccess){Dropbox.appKey=rcmail.env.xdropbox_app_key;Dropbox.choose({success:function success(data){for(var key in data){if(data.hasOwnProperty(key)){data[key]["url"]=data[key]["link"]}}if(typeof onSuccess==="function"){onSuccess(data)}else{xcloud.selectSuccess(data,linkType,"xdropbox")}},linkType:linkType,multiselect:rcmail.env.xdropbox_multiselect,extensions:rcmail.env.xdropbox_extensions})};this.insertSaveButton=function(targetId,mimeId,name,url){$("#"+targetId).append($("<div>").attr("href","javascript:void(0)").addClass("xdropbox-save-button xcloud-save-button").append($("<div>").addClass("image").css("background-image","url('plugins/xdropbox/assets/images/save.png')")).append($("<div>").addClass("text").text(rcmail.gettext("save"))).click(function(){xdropbox.save(mimeId)}))};this.save=function(mimeId){var data=xcloud.saveAttachmentDeployFile(mimeId);var busyId=false;Dropbox.appKey=rcmail.env.xdropbox_app_key;Dropbox.save({files:[{url:xframework.getUrl()+"?xcloud_save="+data.code,filename:data.name}],progress:function progress(_progress){busyId||(busyId=rcmail.set_busy(true,"uploading"))},cancel:function cancel(){xcloud.removeAttachmentDeployFile(data.code)},success:function success(){rcmail.set_busy(false,false,busyId);rcmail.display_message(rcmail.gettext("successfullysaved"),"confirmation")},error:function error(errorMessage){rcmail.set_busy(false,false,busyId);console.log("DROPBOX ERROR: "+errorMessage);rcmail.display_message(rcmail.gettext("errorsaving"),"error")}})}};